namespace sv_30f3e238d4ed49bbbe02203d9a3e47b0.Client.Models;

public sealed class Shipment
{
    public required string TrackingNumber { get; init; }
    public required string Status { get; init; }
    public required string Location { get; init; }
    public DateTimeOffset? EstimatedDelivery { get; init; }
    public required IReadOnlyList<StatusUpdate> StatusUpdates { get; init; }
}

public sealed class StatusUpdate
{
    public required string Description { get; init; }
    public required DateTimeOffset Timestamp { get; init; }
}

using sv_30f3e238d4ed49bbbe02203d9a3e47b0.Client.Models;

namespace sv_30f3e238d4ed49bbbe02203d9a3e47b0.Client.Services;

public interface IShipmentService
{
    Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using sv_30f3e238d4ed49bbbe02203d9a3e47b0.Client.Models;
using sv_30f3e238d4ed49bbbe02203d9a3e47b0.Client.Services;

namespace sv_30f3e238d4ed49bbbe02203d9a3e47b0.Services;

public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new Shipment
        {
            TrackingNumber = "TRK-001",
            Status = "In Transit",
            Location = "Chicago, IL",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 25, 17, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Timestamp = new DateTimeOffset(2026, 5, 20, 9, 0, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "Departed facility in New York, NY", Timestamp = new DateTimeOffset(2026, 5, 21, 6, 30, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "Arrived at sorting center in Chicago, IL", Timestamp = new DateTimeOffset(2026, 5, 22, 14, 0, 0, TimeSpan.Zero) },
            ]
        },
        ["TRK-002"] = new Shipment
        {
            TrackingNumber = "TRK-002",
            Status = "Delivered",
            Location = "San Francisco, CA",
            EstimatedDelivery = null,
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Timestamp = new DateTimeOffset(2026, 5, 15, 10, 0, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "In transit to destination", Timestamp = new DateTimeOffset(2026, 5, 16, 8, 0, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "Out for delivery", Timestamp = new DateTimeOffset(2026, 5, 17, 7, 0, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "Delivered - Left at front door", Timestamp = new DateTimeOffset(2026, 5, 17, 14, 23, 0, TimeSpan.Zero) },
            ]
        },
        ["TRK-003"] = new Shipment
        {
            TrackingNumber = "TRK-003",
            Status = "Processing",
            Location = "Austin, TX",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 28, 12, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Label created", Timestamp = new DateTimeOffset(2026, 5, 22, 8, 0, 0, TimeSpan.Zero) },
                new StatusUpdate { Description = "Awaiting carrier pickup", Timestamp = new DateTimeOffset(2026, 5, 22, 10, 0, 0, TimeSpan.Zero) },
            ]
        }
    };

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        SeedData.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_30f3e238d4ed49bbbe02203d9a3e47b0.Client.Models
@using sv_30f3e238d4ed49bbbe02203d9a3e47b0.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p>Loading shipment details for <strong>@TrackingNumber</strong>...</p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="error-container">
        <p class="error-message">@_errorMessage</p>
        <button @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <div class="not-found">
        <p>No shipment found for tracking number <strong>@TrackingNumber</strong>.</p>
    </div>
}
else
{
    <div class="shipment-details">
        <h2>Shipment @_shipment.TrackingNumber</h2>
        <dl>
            <dt>Status</dt>
            <dd>@_shipment.Status</dd>
            <dt>Location</dt>
            <dd>@_shipment.Location</dd>
            @if (_shipment.EstimatedDelivery.HasValue)
            {
                <dt>Estimated Delivery</dt>
                <dd>@_shipment.EstimatedDelivery.Value.ToString("f")</dd>
            }
        </dl>

        @if (_shipment.StatusUpdates.Count > 0)
        {
            <h3>Tracking History</h3>
            <ul class="status-updates">
                @foreach (var update in _shipment.StatusUpdates)
                {
                    <li>
                        <time datetime="@update.Timestamp.ToString("o")">@update.Timestamp.ToString("g")</time>
                        &mdash; @update.Description
                    </li>
                }
            </ul>
        }
    </div>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = string.Empty;

    private Shipment? _shipment;
    private bool _loading;
    private string? _errorMessage;
    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _loading = true;
        _shipment = null;
        _errorMessage = null;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation changed or component disposed; do nothing.
            return;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
            StateHasChanged();
        }
    }

    private async Task RetryAsync()
    {
        await LoadShipmentAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

